const clients = [
  { name: 'Alfa Construction Inc.', ghlKey: 'YOUR_GHL_KEY', email: 'info@alfapaintingcarpentry.com', site: 'https://www.alfapaintingcarpentry.com/' },
  { name: 'Wolfs Siding Inc', ghlKey: 'YOUR_GHL_KEY', email: 'info@wolfs-siding.com', site: 'https://wolfs-siding.com/' },
  { name: 'RS Development Group', ghlKey: 'YOUR_GHL_KEY', email: 'info@rs-developmentgroup.com', site: 'https://rs-developmentgroup.com/' },
  { name: 'Mass HVAC', ghlKey: 'YOUR_GHL_KEY', email: 'info@masshvac.net', site: 'https://masshvac.net/' },
  { name: 'Maia Construction Inc', ghlKey: 'YOUR_GHL_KEY', email: 'contact@maiaconstruction.com', site: 'https://maiaconstruction.com/' },
  { name: 'JH Painting Services', ghlKey: 'YOUR_GHL_KEY', email: 'contact@jhpaintingservices.com', site: 'https://jhpaintingservices.com/' },
  { name: 'Dorys Cleaning Services', ghlKey: 'YOUR_GHL_KEY', email: 'contact@doryscleaningservices.com', site: 'https://doryscleaningservices.com/' }
];

const TEST_EMAIL = 'galaxyinfomkt@gmail.com';
clients.forEach(c => { c.originalEmail = c.email; c.email = TEST_EMAIL; });

return clients.map(c => ({ json: c }));

const client = $('Lista de Clientes').item.json;
const contactsData = $json;
const now = new Date();
// GSC has 2-3 day data delay; end date = today - 3 days
// Default GSC range = last 28 days (matches what user sees in UI)
const gscEnd = new Date(now.getTime() - 3*24*60*60*1000);
const gscStart = new Date(gscEnd.getTime() - 28*24*60*60*1000);
// Leads range = full 30 days
const leadsStart = new Date(now.getTime() - 30*24*60*60*1000);
return [{ json: {
  ...client,
  _contactsData: contactsData,
  startDate: gscStart.toISOString().split('T')[0],
  endDate: gscEnd.toISOString().split('T')[0],
  leadsStartDate: leadsStart.toISOString().split('T')[0],
  leadsEndDate: now.toISOString().split('T')[0]
}}];

const client = $('Preparar GSC').item.json;
const sitesResp = $json;
const sites = sitesResp.siteEntry || [];

// Extract domain from client site
const clientUrl = client.site.replace(/https?:\/\//, '').replace(/\/$/, '');
const clientDomain = clientUrl.replace(/^www\./, '');

// Find matching site in GSC (prefer domain property, fallback to url-prefix)
let matchedSite = null;
for (const s of sites) {
  const url = s.siteUrl || '';
  if (url === 'sc-domain:' + clientDomain) { matchedSite = url; break; }
}
if (!matchedSite) {
  for (const s of sites) {
    const url = s.siteUrl || '';
    const urlClean = url.replace(/https?:\/\//, '').replace(/\/$/, '').replace(/^www\./, '');
    if (urlClean === clientDomain) { matchedSite = url; break; }
  }
}

return [{ json: {
  ...client,
  gscSiteUrl: matchedSite || '',
  gscAvailable: !!matchedSite,
  allGscSites: sites.map(s => s.siteUrl).join(', ')
}}];

const client = $('Encontrar Site no GSC').item.json;
const contactsData = client._contactsData || {};
const gscData = $json || {};
const allContacts = contactsData.contacts || [];

const now = new Date();
const thirtyAgo = new Date(now.getTime() - 30*24*60*60*1000);
const thirtyAgoMs = thirtyAgo.getTime();

const last30 = allContacts.filter(c => {
  if (!c.dateAdded) return false;
  return new Date(c.dateAdded).getTime() >= thirtyAgoMs;
});

const sources30d = {};
last30.forEach(c => { const s = c.source || c.tags?.[0] || 'Direto'; sources30d[s] = (sources30d[s]||0)+1; });
const sourcesList = Object.entries(sources30d).sort((a,b)=>b[1]-a[1]);
const topSources = sourcesList.slice(0,5).map(([k,v])=>k+' ('+v+')').join(', ') || 'Nenhum lead novo';
const sourcesDetailed = sourcesList.map(([k,v])=>'- ' + k + ': ' + v + ' leads').join('\n') || '- Nenhum lead novo no periodo';

// GSC data processing
let impressions = 0, clicks = 0, avgCtr = '0', avgPos = '0';
const gscRows = gscData.rows || [];
if (gscRows.length > 0) {
  gscRows.forEach(r => { impressions += r.impressions; clicks += r.clicks; });
  avgCtr = impressions > 0 ? ((clicks/impressions)*100).toFixed(2) : '0';
  avgPos = (gscRows.reduce((s,r)=>s+r.position,0) / gscRows.length).toFixed(1);
}
const hasGsc = impressions > 0;
const gscInfo = hasGsc 
  ? 'Impressoes no Google: ' + impressions + ' | Cliques: ' + clicks + ' | CTR: ' + avgCtr + '% | Posicao media: ' + avgPos
  : 'Dados do Google Search Console ainda nao disponiveis (site precisa estar verificado no GSC com a conta da agencia)';

const mesesPT = ['janeiro','fevereiro','março','abril','maio','junho','julho','agosto','setembro','outubro','novembro','dezembro'];
const monthName = mesesPT[now.getMonth()] + ' de ' + now.getFullYear();
const startFmt = thirtyAgo.getDate() + '/' + (thirtyAgo.getMonth()+1) + '/' + thirtyAgo.getFullYear();
const endFmt = now.getDate() + '/' + (now.getMonth()+1) + '/' + now.getFullYear();
const period = startFmt + ' a ' + endFmt;

const prompt = 'IMPORTANTE: Escreva APENAS em portugues brasileiro. NUNCA use ingles.\n\nVoce e redator de relatorios da Galaxy IT & Marketing.\n\nCliente: ' + client.name + '\nSite: ' + client.site + '\nPeriodo: ' + period + '\n\n=== LEADS (ultimos 30 dias) ===\nTotal de novos leads: ' + last30.length + '\n\nDe onde vieram:\n' + sourcesDetailed + '\n\n=== SITE (Google Search Console) ===\n' + gscInfo + '\n\nESTRUTURA DO RELATORIO:\n1. "Ola, equipe da ' + client.name + '!"\n2. Destaques: ' + last30.length + ' novos leads + dados do site (se disponiveis)\n3. De onde vieram os leads: distribuicao por fonte\n4. Desempenho do site no Google (se tiver dados reais de impressoes)\n5. Uma recomendacao baseada nos numeros\n6. "Abracos, Equipe Galaxy IT & Marketing"\n\nREGRAS:\n- TUDO em portugues brasileiro\n- Use os numeros reais acima\n- Se GSC indisponivel, mencione brevemente e foque em leads\n- Maximo 220 palavras';

const body = {
  model: 'llama-3.3-70b-versatile',
  messages: [
    { role: 'system', content: 'Voce e um redator brasileiro. Escreve APENAS em portugues do Brasil. Nunca usa ingles.' },
    { role: 'user', content: prompt }
  ],
  max_tokens: 800,
  temperature: 0.5
};

return [{ json: {
  ...client,
  newContacts: last30.length,
  topSources,
  impressions, clicks, avgCtr, avgPos,
  monthName,
  period,
  aiBody: JSON.stringify(body)
}}];
